320→function base64url(buf: Buffer): string {
321→  return buf.toString("base64url");
322→}
323→
324→function generatePkce(): { verifier: string; challenge: string } {
325→  const verifier = base64url(randomBytes(32));
326→  const challenge = base64url(createHash("sha256").update(verifier).digest());
327→  return { verifier, challenge };
328→}
