574→// ---------------------------------------------------------------------------
575→// DPoP Helpers
576→// ---------------------------------------------------------------------------
577→
578→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
579→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
580→    { name: "ECDSA", namedCurve: "P-256" },
581→    true,
582→    ["sign", "verify"],
583→  );
584→
585→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
586→  const thumbprint = await computeDPoPThumbprint(publicJwk);
587→
588→  return { privateKey, publicKey, publicJwk, thumbprint };
589→}
590→
591→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
592→  const thumbprintInput = JSON.stringify({
593→    crv: publicJwk.crv,
594→    kty: publicJwk.kty,
595→    x: publicJwk.x,
596→    y: publicJwk.y,
597→  });
598→
599→  const hashBuffer = await crypto.subtle.digest(
600→    "SHA-256",
601→    new TextEncoder().encode(thumbprintInput),
602→  );
603→
604→  return base64urlBytes(new Uint8Array(hashBuffer));
605→}
606→
607→async function createDPoPProof(
608→  keyPair: DPoPKeyPair,
609→  method: string,
610→  targetUri: string,
611→): Promise<string> {
612→  const header = {
613→    typ: "dpop+jwt" as const,
614→    alg: "ES256" as const,
615→    jwk: {
616→      kty: keyPair.publicJwk.kty,
617→      crv: keyPair.publicJwk.crv,
618→      x: keyPair.publicJwk.x,
619→      y: keyPair.publicJwk.y,
620→    },
621→  };
622→
623→  const payload = {
624→    jti: crypto.randomUUID(),
625→    htm: method,
626→    htu: targetUri,
627→    iat: Math.floor(Date.now() / 1000),
628→  };
629→
630→  const importedKey = await jose.importJWK(
631→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
632→    "ES256",
633→  );
634→
635→  return await new jose.SignJWT(payload)
636→    .setProtectedHeader(header)
637→    .sign(importedKey);
638→}
639→
640→function base64urlBytes(bytes: Uint8Array): string {
641→  const binary = String.fromCharCode(...bytes);
642→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
643→}
