657→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
658→  return await Promise.race([
659→    callback(),
660→    new Promise<T>((_, reject) => {
661→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
662→    }),
663→  ]);
664→}
