 63→async function seedProject(
 64→  surreal: Surreal,
 65→  workspaceRecord: RecordId<"workspace", string>,
 66→  name: string,
 67→): Promise<RecordId<"project", string>> {
 68→  const projectRecord = new RecordId("project", randomUUID());
