 70→    name,
 71→    status: "active",
 72→    workspace: workspaceRecord,
 73→    created_at: new Date(),
 74→    updated_at: new Date(),
 75→  });
 76→  await surreal
 77→    .relate(workspaceRecord, new RecordId("has_project", randomUUID()), projectRecord, {
 78→      added_at: new Date(),
 79→    })
 80→    .output("after");
 81→  return projectRecord;
 82→}
