 23→describe("Agent Lifecycle: Session start hook", () => {
 24→  // -------------------------------------------------------------------------
 25→  // Happy Path: Agent starts a session on init
 26→  // US-0.1
 27→  // -------------------------------------------------------------------------
 28→  it("creates an agent session when the agent fires session.created", async () => {
 29→    const { baseUrl, surreal } = getRuntime();
 30→
 31→    // Given a coding agent starting up with the Brain MCP integration
 32→    const user = await createTestUser(baseUrl, "lifecycle-start");
 33→    const workspace = await createTestWorkspace(baseUrl, user);
 34→    const tokenUser = await getTestUserBearerToken(baseUrl, surreal, user);
 35→
 36→    // When the agent fires the session.created hook
 37→    const res = await tokenUser.mcpFetch(`/api/mcp/${workspace.workspaceId}/sessions/start`, {
 38→      body: { agent: "claude" },
 39→    });
 40→    const session = await res.json() as { session_id: string };
 41→
 42→    // Then a session is registered for tracking the agent's activity
 43→    expect(session.session_id).toBeTruthy();
 44→  }, 60_000);
