 46→  // -------------------------------------------------------------------------
 47→  // Error Path: Session start without agent identifier
 48→  // -------------------------------------------------------------------------
 49→  it("rejects session start when agent type is not specified", async () => {
 50→    const { baseUrl, surreal } = getRuntime();
 51→
 52→    // Given a hook that fires without identifying the agent
 53→    const user = await createTestUser(baseUrl, "lifecycle-noagent");
 54→    const workspace = await createTestWorkspace(baseUrl, user);
 55→    const tokenUser = await getTestUserBearerToken(baseUrl, surreal, user);
