  1→/**
  2→ * DPoP Verification Middleware
  3→ *
  4→ * Brain resource server pipeline replacing authenticateMcpRequest.
  5→ * Extracts Authorization: DPoP + DPoP headers. Rejects Bearer tokens,
  6→ * session cookies, missing auth with 401 dpop_required.
  7→ * Validates token signature via AS JWKS, validates proof,
  8→ * verifies sender binding (cnf.jkt match).
  9→ *
 10→ * Pure pipeline -- domain logic has no IO imports beyond jose for JWT.
 11→ *
 12→ * Step: 03-01
 13→ */
 14→import * as jose from "jose";
 15→import { RecordId } from "surrealdb";
 16→import { jsonResponse } from "../http/response";
 17→import { validateDPoPProof } from "./dpop";
 18→import type { AsSigningKey } from "./as-key-management";
 19→import type { NonceCache } from "./nonce-cache";
 20→import type { DPoPAuthResult, BrainAction, DPoPBoundTokenClaims } from "./types";
 21→import {
 22→  checkIdentityAllowed,
 23→  type LookupIdentity,
 24→  type LookupManager,
 25→} from "./identity-lifecycle";
 26→import { createAuditEvent, type AuditEvent } from "./audit";
 27→
 28→// ---------------------------------------------------------------------------
 29→// Types
 30→// ---------------------------------------------------------------------------
 31→
 32→/** Workspace lookup port -- pure function signature (no Surreal import in domain). */
 33→export type LookupWorkspace = (
 34→  workspaceId: string,
 35→) => Promise<{ name: string; identityId: string } | undefined>;
 36→
 37→/** Port for fire-and-forget audit event logging. */
 38→export type LogAudit = (event: AuditEvent) => void;
 39→
 40→export type DPoPVerificationDeps = {
 41→  asSigningKey: AsSigningKey;
 42→  nonceCache: NonceCache;
 43→  lookupWorkspace: LookupWorkspace;
 44→  lookupIdentity?: LookupIdentity;
 45→  lookupManager?: LookupManager;
 46→  logAudit?: LogAudit;
 47→};
 48→
 49→// ---------------------------------------------------------------------------
 50→// Error response builders
 51→// ---------------------------------------------------------------------------
 52→
 53→function dpopError(
 54→  error: string,
 55→  status: number,
 56→  errorDescription?: string,
 57→): Response {
 58→  const body: Record<string, string> = { error };
 59→  if (errorDescription) {
 60→    body.error_description = errorDescription;
 61→  }
 62→  return jsonResponse(body, status);
 63→}
 64→
 65→// ---------------------------------------------------------------------------
 66→// Pipeline steps
 67→// ---------------------------------------------------------------------------
 68→
 69→type ExtractedAuth =
 70→  | { type: "dpop"; token: string }
 71→  | { type: "error"; response: Response };
 72→
 73→/** Step 1: Extract and classify the Authorization header. */
 74→function extractAuthorization(request: Request): ExtractedAuth {
 75→  const authHeader = request.headers.get("authorization");
 76→
 77→  // Check for session cookies without DPoP auth
 78→  if (!authHeader) {
 79→    const cookie = request.headers.get("cookie");
 80→    if (cookie && isSessionCookie(cookie)) {
 81→      return {
 82→        type: "error",
 83→        response: dpopError("dpop_required", 401, "Session cookies not accepted. Use DPoP."),
 84→      };
 85→    }
 86→    return {
 87→      type: "error",
 88→      response: dpopError("dpop_required", 401),
 89→    };
 90→  }
 91→
 92→  // Reject Bearer tokens
 93→  if (authHeader.startsWith("Bearer ")) {
 94→    return {
 95→      type: "error",
 96→      response: dpopError(
 97→        "dpop_required",
 98→        401,
 99→        "Bearer tokens not accepted. Use DPoP.",
100→      ),
101→    };
102→  }
103→
104→  // Must be DPoP scheme
105→  if (!authHeader.startsWith("DPoP ")) {
106→    return {
107→      type: "error",
108→      response: dpopError("dpop_required", 401),
109→    };
110→  }
111→
112→  const token = authHeader.slice(5);
113→  if (!token) {
114→    return {
115→      type: "error",
116→      response: dpopError("dpop_required", 401),
117→    };
118→  }
119→
120→  return { type: "dpop", token };
121→}
122→
123→/** Step 2: Extract DPoP proof from request header. */
124→function extractDPoPProof(request: Request): string | Response {
125→  const proof = request.headers.get("dpop");
126→  if (!proof) {
127→    return dpopError(
128→      "invalid_request",
129→      401,
130→      "DPoP proof header required",
131→    );
132→  }
133→  return proof;
134→}
135→
136→/** Step 3: Verify access token JWT signature against AS public key. */
137→async function verifyAccessToken(
138→  token: string,
139→  asSigningKey: AsSigningKey,
140→): Promise<DPoPBoundTokenClaims | Response> {
141→  try {
142→    const publicKey = await jose.importJWK(
143→      asSigningKey.publicJwk as jose.JWK,
144→      "ES256",
145→    );
146→    const { payload } = await jose.jwtVerify(token, publicKey);
147→
148→    // Extract required claims
149→    const sub = payload.sub;
150→    if (!sub) {
151→      return dpopError("invalid_token", 401, "Token missing sub claim");
152→    }
153→
154→    const cnf = payload.cnf as { jkt?: string } | undefined;
155→    if (!cnf?.jkt) {
156→      return dpopError("invalid_token", 401, "Token missing cnf.jkt claim");
157→    }
158→
159→    return {
160→      sub,
161→      iss: payload.iss ?? "",
162→      aud: (Array.isArray(payload.aud) ? payload.aud[0] : payload.aud) ?? "",
163→      exp: payload.exp ?? 0,
164→      iat: payload.iat ?? 0,
165→      cnf: { jkt: cnf.jkt },
166→      authorization_details: (payload.authorization_details ?? []) as BrainAction[],
167→      "urn:brain:intent_id": (payload["urn:brain:intent_id"] ?? "") as string,
168→      "urn:brain:workspace": (payload["urn:brain:workspace"] ?? "") as string,
169→      "urn:brain:actor_type": payload["urn:brain:actor_type"] as string | undefined,
170→    };
171→  } catch {
172→    return dpopError("invalid_token", 401, "Access token signature verification failed");
173→  }
174→}
175→
176→/** Step 4: Validate DPoP proof structure, signature, and claims. */
177→async function validateProof(
178→  proofJwt: string,
179→  method: string,
180→  uri: string,
181→): Promise<{ thumbprint: string; jti: string } | Response> {
182→  const result = await validateDPoPProof(proofJwt, method, uri);
183→
184→  if (!result.valid) {
185→    return dpopError(result.code, 401, result.error);
186→  }
187→
188→  return { thumbprint: result.thumbprint, jti: result.claims.jti };
189→}
190→
191→/** Step 5: Verify sender binding -- proof JWK thumbprint must match token cnf.jkt. */
192→function verifySenderBinding(
193→  proofThumbprint: string,
194→  tokenThumbprint: string,
195→): Response | undefined {
196→  if (proofThumbprint !== tokenThumbprint) {
197→    return dpopError(
198→      "dpop_binding_mismatch",
199→      401,
200→      "DPoP proof key does not match token binding",
201→    );
202→  }
203→  return undefined;
204→}
205→
206→/** Detect session-related cookies (better-auth patterns). */
207→function isSessionCookie(cookie: string): boolean {
208→  return (
209→    cookie.includes("better-auth.session_token") ||
210→    cookie.includes("better-auth.session") ||
211→    cookie.includes("__session")
212→  );
213→}
214→
215→// ---------------------------------------------------------------------------
216→// Audit helper
217→// ---------------------------------------------------------------------------
218→
219→/** Extract identity/workspace from token claims and emit a security audit event. */
220→function emitSecurityAudit(
221→  logAudit: LogAudit | undefined,
222→  claims: DPoPBoundTokenClaims,
223→  eventType: "dpop_rejected" | "security_alert",
224→  payload: Record<string, unknown>,
225→): void {
226→  if (!logAudit) return;
227→
228→  const sub = claims.sub;
229→  const workspaceId = claims["urn:brain:workspace"];
230→  const intentId = claims["urn:brain:intent_id"];
231→
232→  // Extract identity id from sub (format: "identity:<id>")
233→  const identityId = sub.startsWith("identity:") ? sub.slice(9) : sub;
234→
235→  logAudit(createAuditEvent(eventType, {
236→    actor: new RecordId("identity", identityId),
237→    workspace: new RecordId("workspace", workspaceId),
238→    ...(intentId ? { intent_id: new RecordId("intent", intentId) } : {}),
239→    dpop_thumbprint: claims.cnf.jkt,
240→    payload,
241→  }));
242→}
243→
244→// ---------------------------------------------------------------------------
245→// Main middleware
246→// ---------------------------------------------------------------------------
247→
248→/**
249→ * Authenticate a DPoP-protected request.
250→ *
251→ * Returns DPoPAuthResult on success, or an error Response on failure.
252→ * Pure pipeline: extract auth -> extract proof -> verify token -> validate proof
253→ * -> verify binding -> check nonce -> lookup workspace -> build result.
254→ */
255→export async function authenticateDPoPRequest(
256→  request: Request,
257→  deps: DPoPVerificationDeps,
258→): Promise<DPoPAuthResult | Response> {
259→  // Step 1: Extract authorization
260→  const authResult = extractAuthorization(request);
261→  if (authResult.type === "error") {
262→    return authResult.response;
263→  }
264→  const accessToken = authResult.token;
265→
266→  // Step 2: Extract DPoP proof
267→  const proofOrError = extractDPoPProof(request);
268→  if (proofOrError instanceof Response) {
269→    return proofOrError;
270→  }
271→  const proofJwt = proofOrError;
272→
273→  // Step 3: Verify access token signature
274→  const claimsOrError = await verifyAccessToken(accessToken, deps.asSigningKey);
275→  if (claimsOrError instanceof Response) {
276→    return claimsOrError;
277→  }
278→  const claims = claimsOrError;
279→
280→  // Step 4: Validate DPoP proof
281→  const method = request.method;
282→  const uri = request.url;
283→  const proofResultOrError = await validateProof(proofJwt, method, uri);
284→  if (proofResultOrError instanceof Response) {
285→    return proofResultOrError;
286→  }
287→  const { thumbprint: proofThumbprint, jti } = proofResultOrError;
288→
289→  // Step 5: Verify sender binding
290→  const bindingError = verifySenderBinding(proofThumbprint, claims.cnf.jkt);
291→  if (bindingError) {
292→    emitSecurityAudit(deps.logAudit, claims, "dpop_rejected", {
293→      reason: "thumbprint mismatch",
294→      proof_thumbprint: proofThumbprint,
295→      token_thumbprint: claims.cnf.jkt,
296→    });
297→    return bindingError;
298→  }
299→
300→  // Step 6: Check nonce for replay protection
301→  const nonceAllowed = deps.nonceCache.check(jti);
302→  if (!nonceAllowed) {
303→    emitSecurityAudit(deps.logAudit, claims, "security_alert", {
304→      reason: "replay detected",
305→      jti,
306→    });
307→    return dpopError("dpop_proof_reused", 401, "DPoP proof jti has been used");
308→  }
309→
310→  // Step 7: Lookup workspace
311→  const workspaceId = claims["urn:brain:workspace"];
312→  if (!workspaceId) {
313→    return dpopError("invalid_token", 401, "Token missing workspace claim");
314→  }
315→
316→  const workspace = await deps.lookupWorkspace(workspaceId);
317→  if (!workspace) {
318→    return dpopError("invalid_token", 401, "Workspace not found");
319→  }
320→
321→  // Step 8: Check identity lifecycle (revocation) for token subject
322→  if (deps.lookupIdentity && deps.lookupManager) {
323→    // Extract identity id from sub claim (format: "identity:<id>")
324→    const subIdentityId = claims.sub.startsWith("identity:")
325→      ? claims.sub.slice(9)
326→      : claims.sub;
327→
328→    const identityCheck = await checkIdentityAllowed(
329→      subIdentityId,
330→      deps.lookupIdentity,
331→      deps.lookupManager,
332→    );
333→
334→    if (!identityCheck.allowed) {
335→      emitSecurityAudit(deps.logAudit, claims, "security_alert", {
336→        reason: identityCheck.reason,
337→        identity_id: subIdentityId,
338→        alert_type: "revoked_identity",
339→      });
340→      return dpopError(
341→        "identity_blocked",
342→        401,
343→        identityCheck.reason,
344→      );
345→    }
346→  }
347→
348→  // Step 9: Build result
349→  const actorType: "human" | "agent" =
350→    claims["urn:brain:actor_type"] === "human" ? "human" : "agent";
351→
352→  return {
353→    workspaceRecord: new RecordId("workspace", workspaceId),
354→    workspaceName: workspace.name,
355→    identityRecord: new RecordId("identity", workspace.identityId),
356→    actorType,
357→    authorizationDetails: claims.authorization_details,
358→    intentId: claims["urn:brain:intent_id"],
359→    dpopThumbprint: proofThumbprint,
360→  };
361→}
