    expect(res.ok).toBe(true);
  }, 30_000);

  it("Given no commit message in the request body, When commit-check is called, Then a validation error is returned", async () => {
    const { baseUrl, surreal } = getRuntime();
    const user = await createTestUserWithMcp(baseUrl, surreal, "commit-check-empty");

    const workspace = await fetchJson<{ workspaceId: string }>(
      `${baseUrl}/api/workspaces`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json", ...user.headers },
        body: JSON.stringify({ name: `Commit Check Empty ${Date.now()}` }),
      },
    );

    // Link DPoP identity to the API-created workspace
    await surreal.query(`RELATE $identity->member_of->$workspace SET added_at = time::now();`, {
      identity: new RecordId("identity", user.identityId),
      workspace: new RecordId("workspace", workspace.workspaceId),
    });

    const res = await user.mcpFetch(
      `/api/mcp/${workspace.workspaceId}/commits/post-check`,
      {
        body: {},
      },
    );

    expect(res.ok).toBe(false);
    expect(res.status).toBeGreaterThanOrEqual(400);
    expect(res.status).toBeLessThan(500);
  }, 30_000);

