  3→import { RecordId, type Surreal } from "surrealdb";
  4→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
  5→import { createEmbeddingVector } from "../../../app/src/server/graph/embeddings";
  6→import { createTestUserWithMcp, setupAcceptanceSuite, type TestUserWithMcp } from "../acceptance-test-kit";
  7→
  8→// ---------------------------------------------------------------------------
  9→// Setup
 10→// ---------------------------------------------------------------------------
 11→
 12→const getRuntime = setupAcceptanceSuite("intent-context");
 13→
 14→const openrouter = createOpenRouter({ apiKey: process.env.OPENROUTER_API_KEY! });
 15→const embeddingModel = openrouter.textEmbeddingModel(process.env.OPENROUTER_EMBEDDING_MODEL!);
 16→const embeddingDimension = Number(process.env.EMBEDDING_DIMENSION!);
 17→
 18→async function embedText(text: string): Promise<number[] | undefined> {
 19→  return createEmbeddingVector(embeddingModel, text, embeddingDimension);
 20→}
 21→
 22→type IntentContextResponse = {
 23→  level: "task" | "project" | "workspace";
 24→  data: Record<string, unknown>;
 25→};
 26→
 27→// ---------------------------------------------------------------------------
 28→// DPoP-authenticated workspace setup (uses createTestUserWithMcp)
 29→// ---------------------------------------------------------------------------
 30→
 31→type AuthedWorkspace = {
 32→  workspaceId: string;
 33→  workspaceRecord: RecordId<"workspace", string>;
 34→  mcpFetch: TestUserWithMcp["mcpFetch"];
 35→};
 36→
 37→async function createWorkspaceWithOAuth(
 38→  baseUrl: string,
 39→  surreal: Surreal,
 40→  name?: string,
 41→): Promise<AuthedWorkspace> {
 42→  const workspaceId = randomUUID();
 43→  const workspaceRecord = new RecordId("workspace", workspaceId);
 44→  await surreal.query(
 45→    `CREATE $ws CONTENT {
