 56→
 57→  // Get DPoP-capable user for MCP access
 58→  const mcpUser = await createTestUserWithMcp(baseUrl, surreal, `intent-ctx-${Date.now()}-${Math.floor(Math.random() * 10000)}`);
 59→
 60→  // Create member_of edge linking the test identity to THIS workspace (not the one createTestUserWithMcp created)
 61→  const identityRecord = new RecordId("identity", mcpUser.identityId);
 62→  await surreal.query(`RELATE $identity->member_of->$workspace SET added_at = time::now();`, {
 63→    identity: identityRecord,
 64→    workspace: workspaceRecord,
 65→  });
 66→
 67→  return { workspaceId, workspaceRecord, mcpFetch: mcpUser.mcpFetch };
 68→}
 69→
 70→async function seedProject(
 71→  surreal: Surreal,
 72→  workspaceRecord: RecordId<"workspace", string>,
 73→  name: string,
 74→): Promise<RecordId<"project", string>> {
 75→  const projectRecord = new RecordId("project", randomUUID());
 76→  await surreal.create(projectRecord).content({
 77→    name,
 78→    status: "active",
 79→    workspace: workspaceRecord,
 80→    created_at: new Date(),
 81→    updated_at: new Date(),
 82→  });
 83→  await surreal
 84→    .relate(workspaceRecord, new RecordId("has_project", randomUUID()), projectRecord, {
 85→      added_at: new Date(),
 86→    })
 87→    .output("after");
 88→  return projectRecord;
 89→}
 90→
 91→async function seedTask(
 92→  surreal: Surreal,
 93→  workspaceRecord: RecordId<"workspace", string>,
 94→  projectRecord: RecordId<"project", string>,
 95→  title: string,
 96→  embedding?: number[],
 97→): Promise<RecordId<"task", string>> {
 98→  const taskRecord = new RecordId("task", randomUUID());
 99→  await surreal.create(taskRecord).content({
100→    title,
101→    status: "open",
102→    priority: "medium",
103→    workspace: workspaceRecord,
104→    created_at: new Date(),
105→    updated_at: new Date(),
106→    ...(embedding ? { embedding } : {}),
107→  });
108→  await surreal
109→    .relate(taskRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
110→      added_at: new Date(),
111→    })
112→    .output("after");
113→  return taskRecord;
114→}
115→
116→async function seedDecision(
117→  surreal: Surreal,
118→  workspaceRecord: RecordId<"workspace", string>,
119→  projectRecord: RecordId<"project", string>,
120→  summary: string,
121→  status: string,
122→  embedding?: number[],
123→): Promise<RecordId<"decision", string>> {
124→  const decisionRecord = new RecordId("decision", randomUUID());
125→  await surreal.create(decisionRecord).content({
126→    summary,
127→    status,
128→    workspace: workspaceRecord,
129→    created_at: new Date(),
130→    updated_at: new Date(),
131→    ...(embedding ? { embedding } : {}),
132→  });
133→  await surreal
134→    .relate(decisionRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
135→      added_at: new Date(),
136→    })
137→    .output("after");
138→  return decisionRecord;
139→}
