141→async function postContext(
142→  mcpFetch: TestUserWithMcp["mcpFetch"],
143→  workspaceId: string,
144→  body: { intent: string; cwd?: string; paths?: string[] },
145→): Promise<IntentContextResponse> {
146→  const res = await mcpFetch(`/api/mcp/${workspaceId}/context`, { body });
147→  if (!res.ok) throw new Error(`postContext failed: ${res.status} ${await res.text()}`);
148→  return res.json() as Promise<IntentContextResponse>;
149→}
