218→export async function createTestUser(baseUrl: string, suffix: string): Promise<TestUser> {
219→  const email = `test-${Date.now()}-${suffix}@test.local`;
220→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
221→    method: "POST",
222→    headers: { "Content-Type": "application/json" },
223→    body: JSON.stringify({ name: "Test User", email, password: "test-password-123" }),
224→    redirect: "manual",
225→  });
226→
227→  if (!response.ok) {
228→    const body = await response.text();
229→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
230→  }
231→
232→  const setCookie = response.headers.getSetCookie();
233→  if (!setCookie || setCookie.length === 0) {
234→    throw new Error("Sign-up did not return session cookies");
235→  }
236→
237→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
