 33→describe("Review Flow: Viewing agent work for review", () => {
 34→  // -------------------------------------------------------------------------
 35→  // Happy Path: Review shows diff and session summary
 36→  // US-2.1
 37→  // -------------------------------------------------------------------------
 38→  it("review provides diff summary and agent activity trace", async () => {
 39→    const { baseUrl, surreal } = getRuntime();
 40→
 41→    // Given a task where the agent has completed its work
 42→    const user = await createTestUser(baseUrl, "review-view");
 43→    const workspace = await createTestWorkspace(baseUrl, user);
 44→    const task = await createReadyTask(surreal, workspace.workspaceId, {
 45→      title: "Add password strength indicator",
 46→      description: "Show a visual indicator of password strength during registration",
 47→    });
 48→    const assignment = await assignTaskToAgent(
 49→      baseUrl,
 50→      user,
 51→      workspace.workspaceId,
 52→      task.taskId,
 53→    );
 54→
 55→    // Simulate agent completing work
 56→    await simulateSessionStatus(surreal, assignment.agentSessionId, "idle");
 57→
 58→    // When the user views the review for the completed work
 59→    const review = await getReviewSummary(
 60→      baseUrl,
 61→      user,
 62→      workspace.workspaceId,
 63→      assignment.agentSessionId,
 64→    );
 65→
 66→    // Then the review shows which files were changed
 67→    expect(review.diff).toBeDefined();
 68→    expect(review.diff.files).toBeInstanceOf(Array);
 69→    for (const file of review.diff.files) {
 70→      expect(file.path).toBeTruthy();
 71→      expect(["added", "modified", "deleted"]).toContain(file.status);
 72→      expect(typeof file.additions).toBe("number");
 73→      expect(typeof file.deletions).toBe("number");
 74→    }
 75→
 76→    // And the review shows overall change statistics
 77→    expect(typeof review.diff.stats.filesChanged).toBe("number");
 78→
 79→    // And the review includes a trace of the agent's session activity
 80→    expect(review.session).toBeDefined();
 81→    expect(review.session.orchestratorStatus).toBeTruthy();
 82→
 83→    // And the review identifies the task that was worked on
 84→    expect(review.taskTitle).toBe("Add password strength indicator");
 85→  }, 60_000);
 86→
 87→  // -------------------------------------------------------------------------
 88→  // Happy Path: Review shows the branch name for manual inspection
 89→  // US-2.1
 90→  // -------------------------------------------------------------------------
 91→  it("session status includes the branch name for manual code inspection", async () => {
 92→    const { baseUrl, surreal } = getRuntime();
 93→
 94→    // Given a task with completed agent work
