120→describe("Review Flow: Accepting agent work", () => {
121→  // -------------------------------------------------------------------------
122→  // Happy Path: Accept merges changes and completes task
123→  // US-2.2
124→  // -------------------------------------------------------------------------
125→  it("accepting work marks the task as done and completes the session", async () => {
126→    const { baseUrl, surreal } = getRuntime();
127→
128→    // Given completed agent work ready for review
129→    const user = await createTestUser(baseUrl, "review-accept");
130→    const workspace = await createTestWorkspace(baseUrl, user);
