183→      user,
184→      workspace.workspaceId,
185→      task.taskId,
186→    );
187→
188→    const { abortAgentSession } = await import("./orchestrator-test-kit");
189→    await abortAgentSession(
190→      baseUrl,
191→      user,
192→      workspace.workspaceId,
193→      assignment.agentSessionId,
194→    );
195→
196→    // When the user tries to accept the aborted session
197→    const response = await fetchRaw(
198→      `${baseUrl}/api/orchestrator/${workspace.workspaceId}/sessions/${assignment.agentSessionId}/accept`,
199→      {
200→        method: "POST",
201→        headers: { "Content-Type": "application/json", ...user.headers },
202→      },
203→    );
204→
205→    // Then the accept is rejected because the work was already discarded
206→    expect(response.status).toBe(409);
207→  }, 60_000);
208→
209→  // -------------------------------------------------------------------------
210→  // Error Path: Cannot accept a nonexistent session
211→  // -------------------------------------------------------------------------
212→  it("cannot accept work from a nonexistent session", async () => {
213→    const { baseUrl } = getRuntime();
214→
215→    // Given a session identifier that does not exist
216→    const user = await createTestUser(baseUrl, "review-noexist");
217→    const workspace = await createTestWorkspace(baseUrl, user);
218→
219→    // When the user tries to accept a nonexistent session
220→    const response = await fetchRaw(
221→      `${baseUrl}/api/orchestrator/${workspace.workspaceId}/sessions/nonexistent-session/accept`,
222→      {
223→        method: "POST",
224→        headers: { "Content-Type": "application/json", ...user.headers },
225→      },
226→    );
227→
228→    // Then the request fails because no matching session was found
229→    expect(response.status).toBe(404);
230→  }, 30_000);
231→});
