234→  // -------------------------------------------------------------------------
235→  // Happy Path: Rejection sends feedback, agent resumes
236→  // US-2.3
237→  // -------------------------------------------------------------------------
238→  it("rejecting with feedback returns the task to in-progress and the agent continues", async () => {
