110→// ---------------------------------------------------------------------------
111→// Event iteration — port (dependencies as function signatures)
112→// ---------------------------------------------------------------------------
113→
114→export type EventIterationDeps = {
115→  emitEvent: (streamId: string, event: StreamEvent) => void;
116→  updateSessionStatus: (
117→    sessionId: string,
118→    status: OrchestratorStatus,
119→    error?: string,
120→  ) => Promise<void>;
121→  updateLastEventAt: (sessionId: string) => Promise<void>;
122→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
123→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
124→};
125→
126→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
127→  TERMINAL_ORCHESTRATOR_STATUSES,
128→);
129→
130→/**
131→ * Iterates the SDK message stream, forwarding messages through the event
132→ * bridge. Transitions session to "active" on first message, starts stall
133→ * detection, and stops on terminal status or error.
134→ *
135→ * Returns a Promise that resolves when iteration ends (for testing).
136→ * In production, this is launched fire-and-forget.
137→ */
138→export function startEventIteration(
139→  deps: EventIterationDeps,
140→  messageStream: AsyncIterable<unknown>,
141→  streamId: string,
142→  sessionId: string,
143→): Promise<void> {
144→  const stallDetector = deps.startStallDetector(sessionId, streamId);
145→
146→  const bridge = startEventBridge(
147→    {
148→      emitEvent: deps.emitEvent,
149→      updateLastEventAt: deps.updateLastEventAt,
150→    },
151→    streamId,
152→    sessionId,
153→    stallDetector,
154→  );
155→
156→  let firstMessageReceived = false;
157→  let messageCount = 0;
158→
159→  async function iterate(): Promise<void> {
160→    logInfo("orchestrator.iteration", "Event iteration started, awaiting SDK messages", { sessionId, streamId });
161→    try {
162→      for await (const rawMessage of messageStream) {
163→        messageCount++;
164→        const msg = rawMessage as SdkMessage;
165→        logInfo("orchestrator.iteration", `SDK message received (#${messageCount})`, {
166→          sessionId,
167→          messageType: msg.type,
168→          ...(msg.type === "result" ? { subtype: msg.subtype, ...(msg.subtype === "error" ? { error: msg.error } : {}) } : {}),
169→          ...(msg.type === "system" ? { subtype: msg.subtype } : {}),
170→        });
171→
172→        // Check if session has reached terminal status
173→        const currentStatus = await deps.getSessionStatus(sessionId);
174→        if (TERMINAL_STATUSES.has(currentStatus)) {
175→          logInfo("orchestrator.iteration", "Stopping: session reached terminal status", { sessionId, currentStatus });
176→          break;
177→        }
178→
179→        // Transition to active on first message
180→        if (!firstMessageReceived) {
181→          firstMessageReceived = true;
182→          await deps.updateSessionStatus(sessionId, "active");
183→        }
184→
185→        // Forward through event bridge (transform + emit + stall detection)
186→        bridge.handleMessage(msg);
187→      }
188→      logInfo("orchestrator.iteration", "Event iteration ended normally", { sessionId, messageCount });
189→      // Transition to idle when stream ends normally and agent produced output
190→      if (firstMessageReceived) {
191→        const finalStatus = await deps.getSessionStatus(sessionId);
192→        if (!TERMINAL_STATUSES.has(finalStatus)) {
193→          await deps.updateSessionStatus(sessionId, "idle");
194→        }
195→      }
196→    } catch (err) {
197→      const errorMessage = err instanceof Error ? err.message : String(err);
198→      logError("orchestrator.iteration", "Agent message stream error", err, { sessionId, streamId });
199→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
200→    } finally {

696→// getOrchestratorReview
697→// ---------------------------------------------------------------------------
698→
699→type GetReviewInput = {
700→  surreal: Surreal;
701→  sessionId: string;
702→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
703→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
704→  getTaskTitle: (taskId: string) => Promise<string>;
705→};
706→
707→export async function getOrchestratorReview(
708→  input: GetReviewInput,
709→): Promise<ReviewResult> {
710→  const lookup = await lookupSession(input.surreal, input.sessionId);
711→  if (!lookup.ok) {
712→    return { ok: false, error: lookup.error };
713→  }
714→  const { session, status } = lookup;
715→
716→  if (status === "aborted") {
717→    return { ok: false, error: sessionAborted(input.sessionId) };
718→  }
719→
720→  if (!REVIEWABLE_STATUSES.has(status)) {
721→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
722→  }
723→
724→  // Get diff from the branch
725→  const branchName = session.worktree_branch ?? "";
726→  const workspaceRecord = requireWorkspace(session, input.sessionId);
727→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
728→  const diffResult = await input.getDiff(repoRoot, branchName);
729→
730→  const diff = diffResult.ok
731→    ? diffResult.value
732→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
733→
734→  // Get task title
735→  const taskId = session.task_id ? session.task_id.id : "";
736→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
737→
738→  return {
739→    ok: true,
740→    value: {
741→      taskTitle,
742→      diff,
743→      session: {
744→        orchestratorStatus: status,
745→        ...pickDefined({
746→          worktreeBranch: session.worktree_branch,
747→          startedAt: session.started_at,
748→          lastEventAt: session.last_event_at,
